+        receipt.sign(&signer_a).expect("sign must succeed");
+
+        let err = receipt
+            .verify_signature(&verifier_b)
+            .expect_err("cross-key verification must not succeed");
+        assert!(matches!(err, AuditError::SignatureInvalid { .. }));
+    }
